# Computing standard metrics with pycocoevalcap (standard COCO evaluation)
# Install: pip install pycocoevalcap pycocotools
from pycocoevalcap.bleu.bleu import Bleu
from pycocoevalcap.meteor.meteor import Meteor
from pycocoevalcap.cider.cider import Cider
from pycocoevalcap.spice.spice import Spice

def evaluate_captions(references, hypotheses):
    """
    references: dict {image_id: ["ref caption 1", "ref caption 2", ...]}
    hypotheses: dict {image_id: ["generated caption"]}
    """
    scorers = [
        (Bleu(4), ["Bleu_1", "Bleu_2", "Bleu_3", "Bleu_4"]),
        (Meteor(), "METEOR"),
        (Cider(), "CIDEr"),
    ]
    results = {}
    for scorer, method in scorers:
        score, _ = scorer.compute_score(references, hypotheses)
        if isinstance(method, list):
            for m, s in zip(method, score):
                results[m] = round(s, 4)
        else:
            results[method] = round(score, 4)
    return results

# Example usage
refs  = {0: ["a dog runs on the grass", "a brown dog is running"]}
hyps  = {0: ["a dog is running on a green lawn"]}
print(evaluate_captions(refs, hyps))
# {'Bleu_4': 0.1954, 'METEOR': 0.3821, 'CIDEr': 0.7124}
